import React from "react";
import classes from './MyPosts.module.css';
import Post from "./Post/Post";
import {Field, reduxForm} from "redux-form";
import {required} from "../../../utils/validators/validators";
import {Area} from "../../Common/FormsControls/FormsControls";

const Textarea = Area('textarea')

let AddNewPostForm = (props) => {
    return <form onSubmit={props.handleSubmit}>
        <div>
                       <Field className={classes.textarea} component={Textarea} placeholder={'Enter new post'} name={'newPostBody'}/>
            <div>
                <button className={classes.button}> Add post</button>
            </div>
        </div>
    </form>
};
const AddNewPostFormRedux = reduxForm({form: 'profileAddPostForm'})(AddNewPostForm);

const Photo = (props) => {
    return <img src={props.profile.photos.small}/>
}

const MyPosts = React.memo(props => {

    //Оптимизация рендера
    //Классовая компонента
    //оптимизация рендера равны ли пропсы или стэйт
    // shouldComponentUpdate(nextProps, nextState) {
//            return nextProps != this.props || nextState != this.state;
// }
    // class MyPosts extends PureComponent
    //Оптимизация рендера функциональной компоненты
    // const MyPosts = React.memo (props => {})


//оптимизация рендера равны ли пропсы или стэйт
// shouldComponentUpdate(nextProps, nextState) {
//            return nextProps != this.props || nextState != this.state;
// }


    let postsElements =
        //вариант с копированием пропсов т.к. метод реверс изменяет стэйт
        [...props.posts]
                .reverse()
            .map(p => <Post post={p.post} key={p.id} likesCount={p.likesCount}/>);
    //Изначально так было просто отображение в пропсах
    // props.posts.map(p => <Post post={p.post} key={p.id} likesCount={p.likesCount}/>);

    // let newPostElement = React.createRef(); //1. создаем переменную-ссылку newPostElement. Это ссылка- React.createRef()

    // присваиваем значение фунции addPost из state здесь локально  */}
    // let onAddPost = () => {
    //     props.addPost();
    // }
    //
    let addNewPost = (value) => {
        props.addPost(value.newPostBody);
    }


    //* функция вводит данные из state которые бфли внесены в текстареа*
    // let onPostChange = () => {
    //     let text = newPostElement.current.value;
    //     props.updateNewPostText(text);
    // }
debugger
    return <div className={classes.content}>
        <div> <img src={props.profile.photos.small}/></div>
        <span className={classes.text}><b>My posts</b></span>
        <div className={classes.addpost}>
        <AddNewPostFormRedux onSubmit={addNewPost}/>
    </div>
        <div className={classes.posts}>
            {postsElements}
               </div>

    </div>
})

// const maxLength10 = maxLengthCreator(10);


export default MyPosts;
